"""Repository scanner implementation."""

from __future__ import annotations

import hashlib
import os
from pathlib import Path
from typing import Literal, cast

from agentheim_code.vendor.aictx.git.status import WorktreeStatus
from agentheim_code.vendor.aictx.models.inventory import FileEntry, GitStatusSnapshot, RepositoryInventory, SecretFinding
from agentheim_code.vendor.aictx.scan.classify import classify_project
from agentheim_code.vendor.aictx.scan.ignore import IgnoreMatcher
from agentheim_code.vendor.aictx.scan.secrets import scan_for_secrets

EXTENSION_LANGUAGE_MAP = {
    ".py": "python",
    ".cs": "csharp",
    ".xaml": "xaml",
    ".ts": "typescript",
    ".tsx": "typescript",
    ".js": "javascript",
    ".jsx": "javascript",
    ".rs": "rust",
    ".go": "go",
    ".java": "java",
    ".kt": "kotlin",
    ".fs": "fsharp",
    ".fsx": "fsharp",
    ".fsproj": "fsharp",
    ".csproj": "csharp",
    ".toml": "toml",
    ".json": "json",
    ".yml": "yaml",
    ".yaml": "yaml",
    ".md": "markdown",
}

MANIFEST_PATTERNS = {
    "pyproject.toml",
    "package.json",
    "Cargo.toml",
    "go.mod",
    ".github/workflows",
}

TEST_PATH_PATTERNS = ["tests/", "test_", "_test.", ".Tests/", "Tests.cs", ".test.", ".spec."]
GENERATED_CONTEXT_PREFIX = "docs/AIprojectcontext/"
GENERATED_AGENTS_MARKER = "**Generated by:** `aictx`"


def _is_binary(path: Path) -> bool:
    """Conservative binary-file check."""
    try:
        with path.open("rb") as fh:
            chunk = fh.read(8192)
    except OSError:
        return True
    if not chunk:
        return False
    # If null bytes present, treat as binary
    if b"\x00" in chunk:
        return True
    # If high ratio of non-printable bytes, treat as binary
    non_text = sum(1 for b in chunk if b < 0x09 or (0x0E <= b <= 0x1F and b not in (0x0A, 0x0D)))
    return non_text > len(chunk) * 0.3


def _sha256_file(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as fh:
        for chunk in iter(lambda: fh.read(65536), b""):
            h.update(chunk)
    return h.hexdigest()


def _detect_language(path: Path) -> str | None:
    ext = path.suffix.lower()
    return EXTENSION_LANGUAGE_MAP.get(ext)


def _is_manifest(path: Path) -> bool:
    name = path.name
    if name in {"pyproject.toml", "package.json", "Cargo.toml", "go.mod"}:
        return True
    return ".github/workflows" in path.as_posix()


def _is_test(path: Path) -> bool:
    posix = path.as_posix()
    return any(pat in posix for pat in TEST_PATH_PATTERNS)


def _is_doc(path: Path) -> bool:
    name = path.name
    if name in {"README.md", "CHANGELOG.md", "ROADMAP.md", "AGENTS.md"}:
        return True
    if path.suffix == ".md":
        return True
    return "docs/" in path.as_posix()


def _is_generated_artifact(relative_path: str, path: Path, is_binary: bool) -> bool:
    """Return True for files produced by the aictx context generator."""
    if relative_path.startswith(GENERATED_CONTEXT_PREFIX):
        return True
    if relative_path == "AGENTS.md" and not is_binary:
        try:
            return GENERATED_AGENTS_MARKER in path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            return False
    return False


def scan_repository(repo_root: Path) -> RepositoryInventory:
    """Scan *repo_root* and return a deterministic inventory."""
    git_status = WorktreeStatus(repo_root)
    git_snapshot = GitStatusSnapshot(
        is_dirty=git_status.dirty,
        tracked_files=sorted(git_status.tracked_files),
        untracked_files=sorted(git_status.untracked_files),
        modified_files=sorted(git_status.modified_files),
        deleted_files=sorted(git_status.deleted_files),
        renamed_files=sorted(git_status.renamed_files, key=lambda item: (item["from"], item["to"])),
    )
    matcher = IgnoreMatcher(repo_root)
    classification = classify_project(repo_root)

    files: list[FileEntry] = []
    docs: list[FileEntry] = []
    manifests: list[FileEntry] = []
    all_secrets: list[SecretFinding] = []

    build_systems: set[str] = set()
    detected_languages: set[str] = set()
    entrypoints: list[str] = []
    test_projects: list[str] = []

    for root, dirs, filenames in os.walk(repo_root):
        rel_root = Path(root).relative_to(repo_root)
        # Prune ignored directories before descending
        dirs[:] = [
            d for d in dirs if not matcher.is_ignored((rel_root / d).as_posix(), is_dir=True)
        ]
        for fname in filenames:
            full = Path(root) / fname
            rel_posix = (rel_root / fname).as_posix()
            if rel_posix.startswith("./"):
                rel_posix = rel_posix[2:]

            # Skip symlinks
            if full.is_symlink():
                continue

            is_ignored = matcher.is_ignored(rel_posix)
            size = full.stat().st_size
            binary = _is_binary(full)
            is_generated = _is_generated_artifact(rel_posix, full, binary)

            # Skip hashing for binaries and huge files
            sha = _sha256_file(full) if not binary and size <= 250_000 else "skipped"

            lang = _detect_language(full)
            if lang:
                detected_languages.add(lang)

            is_manifest = _is_manifest(full)
            is_test = _is_test(full)
            is_doc = _is_doc(full)
            is_source = (
                bool(lang) and not is_test and not is_doc and not is_manifest and not is_generated
            )

            if is_manifest:
                build_systems.add(full.name)

            kind: str = "other"
            if is_ignored:
                kind = "ignored"
            elif is_generated:
                kind = "generated"
            elif binary:
                kind = "binary"
            elif is_doc:
                kind = "doc"
            elif is_manifest:
                kind = "manifest"
            elif is_test:
                kind = "test"
            elif is_source:
                kind = "source"

            entry = FileEntry(
                path=rel_posix,
                kind=kind,  # type: ignore[arg-type]
                language=lang,
                size_bytes=size,
                sha256=sha,
                is_doc=is_doc,
                is_source=is_source,
                is_test=is_test,
                is_manifest=is_manifest,
                is_generated=is_generated,
                is_binary=binary,
                is_ignored=is_ignored,
                include_reason=None if is_ignored else kind,
                exclude_reason="ignored" if is_ignored else None,
            )

            if is_ignored:
                files.append(entry)
                continue

            if is_doc and not is_generated:
                docs.append(entry)
            elif is_manifest and not is_generated:
                manifests.append(entry)

            if not binary and not is_ignored:
                try:
                    content = full.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    content = ""
                raw_findings = scan_for_secrets(content, Path(rel_posix))
                for finding in raw_findings:
                    line_number = cast(int | None, finding.get("line_number"))
                    all_secrets.append(
                        SecretFinding(
                            path=cast(str, finding["path"]),
                            detector_name=cast(str, finding["detector_name"]),
                            severity=cast(Literal["high", "medium", "low"], finding["severity"]),
                            line_number=line_number,
                        )
                    )

            files.append(entry)

    # Deterministic sort
    files.sort(key=lambda e: e.path)
    docs.sort(key=lambda e: e.path)
    manifests.sort(key=lambda e: e.path)

    # Basic entrypoint heuristic
    if classification.get("project_type") == "python_cli":
        for e in files:
            if e.path.endswith("cli.py"):
                entrypoints.append(e.path)

    return RepositoryInventory(
        repo_root=str(repo_root.resolve()),
        branch=git_status.branch,
        head_commit=git_status.head_commit,
        dirty_state=git_status.dirty,
        git_status=git_snapshot,
        files=files,
        docs=docs,
        manifests=manifests,
        build_systems=sorted(build_systems),
        detected_languages=sorted(detected_languages),
        project_classification=classification,
        entrypoints=entrypoints,
        test_projects=sorted(test_projects),
        secrets=all_secrets,
    )
